#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        int maxLen=0, secondLen=0, cur=0;
        for(int i=0;i<N;i++){
            if(a[i]==0) cur++;
            else{
                if(cur>maxLen){ secondLen=maxLen; maxLen=cur; }
                else if(cur>secondLen){ secondLen=cur; }
                cur=0;
            }
        }
        free(a);
        int win = (maxLen%2==1) && ((maxLen+1)/2 > secondLen);
        printf("%s\n", win?"Yes":"No");
    }
    return 0;
}

