import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        max_len = second_len = cur = 0
        for _ in range(N):
            x = int(next(it))
            if x == 0:
                cur += 1
            else:
                if cur > max_len:
                    second_len = max_len
                    max_len = cur
                elif cur > second_len:
                    second_len = cur
                cur = 0
        win = (max_len % 2 == 1) and ((max_len + 1) // 2 > second_len)
        out.append('Yes' if win else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

